import { Module } from '@medusajs/framework/utils'

import MeilisearchModuleService from './service'

export const MEILISEARCH_MODULE = 'meilisearch'
export { MeilisearchModuleService }

export default Module(MEILISEARCH_MODULE, {
  service: MeilisearchModuleService,
})

import { MeiliSearch } from 'meilisearch'

import { IndexType, MeilisearchEntity, MeilisearchSearchResult } from './types'

type ModuleOptions = {
  host: string
  apiKey: string
}

const SEARCHABLE_ATTRIBUTES = [
  'title',
  'subtitle',
  'description',
  'tags.value',
  'type.value',
  'categories.name',
  'collection.title',
  'variants.title',
  'seller.name',
  'seller.handle',
]

const FILTERABLE_ATTRIBUTES = [
  'seller.status',
  'seller.handle',
  'categories.id',
  'categories.name',
  'variants.prices.amount',
  'status',
]

const SORTABLE_ATTRIBUTES = ['title', 'variants.prices.amount']

class MeilisearchModuleService {
  private client_: MeiliSearch

  constructor(_: unknown, options: ModuleOptions) {
    if (!options?.host || !options?.apiKey) {
      const missing = [
        !options?.host && 'MEILISEARCH_HOST',
        !options?.apiKey && 'MEILISEARCH_API_KEY',
      ]
        .filter(Boolean)
        .join(', ')
      throw new Error(
        `[meilisearch block] Missing required environment variables: ${missing}`
      )
    }
    this.client_ = new MeiliSearch({
      host: options.host,
      apiKey: options.apiKey,
    })
  }

  getHost(): string {
    return (this.client_ as any).config?.host ?? ''
  }

  async getStatus(): Promise<{ documentCount: number; isHealthy: boolean }> {
    try {
      const index = this.client_.index(IndexType.PRODUCT)
      const stats = await index.getStats()
      return { documentCount: stats.numberOfDocuments, isHealthy: true }
    } catch {
      return { documentCount: 0, isHealthy: false }
    }
  }

  async batchUpsert(documents: MeilisearchEntity[]): Promise<void> {
    if (!documents.length) {
      return
    }
    const index = this.client_.index(IndexType.PRODUCT)
    await index.addDocuments(documents, { primaryKey: 'id' })
  }

  async batchDelete(ids: string[]): Promise<void> {
    if (!ids.length) {
      return
    }
    const index = this.client_.index(IndexType.PRODUCT)
    await index.deleteDocuments(ids)
  }

  async search(
    query: string,
    options: Record<string, unknown>
  ): Promise<MeilisearchSearchResult> {
    const index = this.client_.index(IndexType.PRODUCT)
    const result = await index.search(query, options)
    return {
      hits: (result.hits ?? []) as Array<{ id: string }>,
      totalHits: result.totalHits ?? result.estimatedTotalHits ?? 0,
      page: result.page ?? 0,
      totalPages: result.totalPages ?? 0,
      hitsPerPage: result.hitsPerPage ?? 0,
      processingTimeMs: result.processingTimeMs,
      query: result.query,
      facetDistribution: result.facetDistribution,
    }
  }

  async ensureSettings(): Promise<void> {
    const index = this.client_.index(IndexType.PRODUCT)
    await index.updateSettings({
      searchableAttributes: SEARCHABLE_ATTRIBUTES,
      filterableAttributes: FILTERABLE_ATTRIBUTES,
      sortableAttributes: SORTABLE_ATTRIBUTES,
    })
  }
}

export default MeilisearchModuleService

import { z } from 'zod'

import { MedusaContainer } from '@medusajs/framework'
import { ContainerRegistrationKeys, arrayDifference } from '@medusajs/framework/utils'

import { MeilisearchProductValidator, MeilisearchVariantValidator } from '../../modules/meilisearch/types'

export async function filterProductsByStatus(
  container: MedusaContainer,
  ids: string[] = []
) {
  const query = container.resolve(ContainerRegistrationKeys.QUERY)

  const { data: products } = await query.graph({
    entity: 'product',
    fields: ['id', 'status'],
    filters: { id: ids },
  })

  const published = products.filter((p) => p.status === 'published')
  const notPublished = arrayDifference(products, published)

  const existingIds = new Set(products.map((p) => p.id))
  const deletedIds = ids.filter((id) => !existingIds.has(id))

  return {
    published: published.map((p) => p.id),
    other: [...notPublished.map((p) => p.id), ...deletedIds],
  }
}

export async function findAndTransformMeilisearchProducts(
  container: MedusaContainer,
  ids: string[] = []
) {
  const query = container.resolve(ContainerRegistrationKeys.QUERY)

  const { data: products } = await query.graph({
    entity: 'product',
    fields: [
      '*',
      'categories.name',
      'categories.id',
      'collection.title',
      'tags.value',
      'type.value',
      'variants.*',
      'variants.options.*',
      'variants.options.prices.*',
      'variants.prices.*',
      'options.*',
      'options.values.*',
      'images.*',
      'seller.id',
      'seller.handle',
      'seller.name',
      'seller.status',
    ],
    filters: ids.length
      ? { id: ids, status: 'published' }
      : { status: 'published' },
  })

  for (const product of products as any[]) {
    product.options = (product.options ?? [])
      .filter((option: any) => option?.title && option?.values)
      .map((option: any) =>
        option.values.map((value: any) => {
          const entry: Record<string, string> = {}
          entry[option.title.toLowerCase()] = value.value
          return entry
        })
      )
      .flat()

    product.variants = z
      .array(MeilisearchVariantValidator)
      .parse(product.variants ?? [])

    product.variants = (product.variants ?? []).map((variant: any) =>
      (variant.options ?? []).reduce((entry: any, item: any) => {
        if (item?.option?.title) {
          entry[item.option.title.toLowerCase()] = item.value
        }
        return entry
      }, variant)
    )
  }

  return z.array(MeilisearchProductValidator).parse(products)
}

import { SubscriberArgs, SubscriberConfig } from '@medusajs/framework'
import { IEventBusModuleService } from '@medusajs/framework/types'
import { ContainerRegistrationKeys, Modules } from '@medusajs/framework/utils'

import { MeilisearchEvents } from '../modules/meilisearch/types'

export default async function meilisearchProductEventsBridgeHandler({
  event,
  container,
}: SubscriberArgs<{ id: string }>) {
  const logger = container.resolve(ContainerRegistrationKeys.LOGGER)
  const eventBus = container.resolve<IEventBusModuleService>(Modules.EVENT_BUS)

  try {
    const isDelete =
      event.name === 'product.product.deleted' ||
      event.name === 'product.deleted'

    await eventBus.emit({
      name: isDelete
        ? MeilisearchEvents.PRODUCTS_DELETED
        : MeilisearchEvents.PRODUCTS_CHANGED,
      data: { ids: [event.data.id] },
    })
  } catch (error: unknown) {
    logger.error(
      `Meilisearch bridge: failed to forward event ${event.name} for product ${event.data.id}:`,
      error as Error
    )
    throw error
  }
}

export const config: SubscriberConfig = {
  event: [
    'product.created',
    'product.updated',
    'product.deleted',
    'product.product.created',
    'product.product.updated',
    'product.product.deleted',
  ],
  context: {
    subscriberId: 'meilisearch-product-events-bridge',
  },
}

import { SubscriberArgs, SubscriberConfig } from '@medusajs/framework'
import { ContainerRegistrationKeys } from '@medusajs/framework/utils'

import { MEILISEARCH_MODULE, MeilisearchModuleService } from '../modules/meilisearch'
import { MeilisearchEvents } from '../modules/meilisearch/types'
import {
  filterProductsByStatus,
  findAndTransformMeilisearchProducts,
} from './utils/meilisearch-product'

export default async function meilisearchProductsChangedHandler({
  event,
  container,
}: SubscriberArgs<{ ids: string[] }>) {
  const logger = container.resolve(ContainerRegistrationKeys.LOGGER)

  try {
    const meilisearch =
      container.resolve<MeilisearchModuleService>(MEILISEARCH_MODULE)

    const { published, other } = await filterProductsByStatus(
      container,
      event.data.ids
    )

    logger.debug(
      `Meilisearch sync: Processing ${event.data.ids.length} products — ${published.length} to upsert, ${other.length} to delete`
    )

    const documentsToUpsert = published.length
      ? await findAndTransformMeilisearchProducts(container, published)
      : []

    if (documentsToUpsert.length) {
      await meilisearch.batchUpsert(documentsToUpsert)
    }
    if (other.length) {
      await meilisearch.batchDelete(other)
    }

    logger.debug(
      `Meilisearch sync: Successfully synced ${documentsToUpsert.length} products`
    )
  } catch (error: unknown) {
    logger.error(
      `Meilisearch sync failed for products [${event.data.ids.join(', ')}]:`,
      error as Error
    )
    throw error
  }
}

export const config: SubscriberConfig = {
  event: MeilisearchEvents.PRODUCTS_CHANGED,
  context: {
    subscriberId: 'meilisearch-products-changed-handler',
  },
}

