import { IEventBusModuleService, RemoteQueryFunction } from '@medusajs/framework/types'
import { ContainerRegistrationKeys, Modules } from '@medusajs/framework/utils'
import { StepResponse, createStep } from '@medusajs/framework/workflows-sdk'

import { MEILISEARCH_MODULE, MeilisearchModuleService } from '../../../modules/meilisearch'
import { MeilisearchEvents } from '../../../modules/meilisearch/types'

const CHUNK_SIZE = 100

export const syncMeilisearchProductsStep = createStep(
  'sync-meilisearch-products',
  async (_: void, { container }) => {
    const query = container.resolve<RemoteQueryFunction>(
      ContainerRegistrationKeys.QUERY
    )
    const meilisearch =
      container.resolve<MeilisearchModuleService>(MEILISEARCH_MODULE)
    const eventBus = container.resolve<IEventBusModuleService>(Modules.EVENT_BUS)

    // Delete products that are not published or have been soft-deleted
    const { data: productsToDelete } = await query.graph({
      entity: 'product',
      filters: {
        status: { $ne: 'published' },
      },
      fields: ['id'],
    })

    if (productsToDelete.length) {
      await meilisearch.batchDelete(productsToDelete.map((p) => p.id))
    }

    // Fetch all published product IDs and process in chunks
    const { data: publishedProducts } = await query.graph({
      entity: 'product',
      filters: { status: 'published' },
      fields: ['id'],
    })

    const productIds = publishedProducts.map((p) => p.id)

    for (let i = 0; i < productIds.length; i += CHUNK_SIZE) {
      const chunk = productIds.slice(i, i + CHUNK_SIZE)
      await eventBus.emit({
        name: MeilisearchEvents.PRODUCTS_CHANGED,
        data: { ids: chunk },
      })
    }

    return new StepResponse()
  }
)

import { createWorkflow, WorkflowResponse } from '@medusajs/framework/workflows-sdk'

import { syncMeilisearchProductsStep } from '../steps/sync-meilisearch-products'

export const syncMeilisearchWorkflow = createWorkflow(
  'sync-meilisearch-workflow',
  function () {
    return new WorkflowResponse(syncMeilisearchProductsStep())
  }
)

import { AuthenticatedMedusaRequest, MedusaResponse } from '@medusajs/framework'

import { MEILISEARCH_MODULE, MeilisearchModuleService } from '../../../modules/meilisearch'
import { IndexType } from '../../../modules/meilisearch/types'
import { syncMeilisearchWorkflow } from '../../../workflows/meilisearch/workflows/sync-meilisearch'

export const POST = async (
  req: AuthenticatedMedusaRequest,
  res: MedusaResponse
) => {
  await syncMeilisearchWorkflow.run({
    container: req.scope,
  })

  res.status(200).json({ message: 'Sync in progress' })
}

export const GET = async (
  req: AuthenticatedMedusaRequest,
  res: MedusaResponse
) => {
  const meilisearch =
    req.scope.resolve<MeilisearchModuleService>(MEILISEARCH_MODULE)

  const host = meilisearch.getHost()
  const { documentCount, isHealthy } = await meilisearch.getStatus()

  res.status(200).json({
    host,
    index: IndexType.PRODUCT,
    documentCount,
    isHealthy,
  })
}

import { MiddlewareRoute, validateAndTransformBody } from '@medusajs/framework'

import { StoreMeilisearchSearchSchema } from './validators'

export const meilisearchStoreMiddlewares: MiddlewareRoute[] = [
  {
    methods: ['POST'],
    matcher: '/store/meilisearch/products/search',
    middlewares: [validateAndTransformBody(StoreMeilisearchSearchSchema)],
  },
]

import { MedusaRequest, MedusaResponse } from '@medusajs/framework'
import { ContainerRegistrationKeys, QueryContext } from '@medusajs/framework/utils'

import { MEILISEARCH_MODULE, MeilisearchModuleService } from '../../../../../modules/meilisearch'
import { IndexType } from '../../../../../modules/meilisearch/types'
import { StoreMeilisearchSearchType } from './validators'

export const POST = async (
  req: MedusaRequest<StoreMeilisearchSearchType>,
  res: MedusaResponse
) => {
  const meilisearchService =
    req.scope.resolve<MeilisearchModuleService>(MEILISEARCH_MODULE)
  const query = req.scope.resolve(ContainerRegistrationKeys.QUERY)

  const {
    query: searchQuery,
    page,
    hitsPerPage,
    filters,
    currency_code,
    region_id,
    customer_id,
    customer_group_id,
  } = req.validatedBody

  // Build filter string server-side — seller.status = "active" is always enforced (FR-003)
  const filterParts: string[] = ['seller.status = "active"']

  if (filters?.categories?.length) {
    const ids = filters.categories.map((c) => `"${c}"`).join(', ')
    filterParts.push(`categories.id IN [${ids}]`)
  }
  if (filters?.price_min !== undefined) {
    filterParts.push(`variants.prices.amount >= ${filters.price_min}`)
  }
  if (filters?.price_max !== undefined) {
    filterParts.push(`variants.prices.amount <= ${filters.price_max}`)
  }
  if (filters?.seller_handle) {
    filterParts.push(`seller.handle = "${filters.seller_handle}"`)
  }

  const filter = filterParts.join(' AND ')

  const searchResult = await meilisearchService.search(searchQuery, {
    filter,
    page,
    hitsPerPage,
    attributesToRetrieve: ['id'],
  })

  const productIds = searchResult.hits.map((hit) => hit.id)

  if (!productIds.length) {
    return res.json({
      products: [],
      totalHits: searchResult.totalHits,
      page: searchResult.page,
      totalPages: searchResult.totalPages,
      hitsPerPage: searchResult.hitsPerPage,
      processingTimeMs: searchResult.processingTimeMs,
      query: searchResult.query,
    })
  }

  const hasPricingContext =
    currency_code || region_id || customer_id || customer_group_id

  const contextParams: Record<string, unknown> = {}
  if (hasPricingContext) {
    contextParams.variants = {
      calculated_price: QueryContext({
        ...(currency_code && { currency_code }),
        ...(region_id && { region_id }),
        ...(customer_id && { customer_id }),
        ...(customer_group_id && { customer_group_id }),
      }),
    }
  }

  const { data: products } = await query.graph({
    entity: 'product',
    fields: [
      '*',
      'images.*',
      'options.*',
      'options.values.*',
      'variants.*',
      'variants.options.*',
      'variants.prices.*',
      ...(hasPricingContext ? ['variants.calculated_price.*'] : []),
      'categories.*',
      'collection.*',
      'type.*',
      'tags.*',
      'seller.*',
    ],
    filters: { id: productIds },
    ...(Object.keys(contextParams).length > 0 && { context: contextParams }),
  })

  const productMap = new Map(products.map((p) => [p.id, p]))
  const orderedProducts = productIds.map((id) => productMap.get(id)).filter(Boolean)

  return res.json({
    products: orderedProducts,
    totalHits: searchResult.totalHits,
    page: searchResult.page,
    totalPages: searchResult.totalPages,
    hitsPerPage: searchResult.hitsPerPage,
    processingTimeMs: searchResult.processingTimeMs,
    query: searchResult.query,
    facetDistribution: searchResult.facetDistribution,
  })
}
